import{_ as n,o as a,c as s,a as t}from"./app-d76978d4.js";const p={},o=t(`<h1 id="control-flow" tabindex="-1"><a class="header-anchor" href="#control-flow" aria-hidden="true">#</a> Control flow</h1><h2 id="if" tabindex="-1"><a class="header-anchor" href="#if" aria-hidden="true">#</a> <code>if</code></h2><p>The <code>if</code> statement is pretty much what you would expect.</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token comment">// The usual</span>
<span class="token keyword">if</span> <span class="token punctuation">(</span>someCondition<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>anotherCondition<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
<span class="token punctuation">}</span>
</code></pre></div><p>You can unwrap an optional with the <code>-&gt;</code> operator.</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>opt <span class="token operator">-&gt;</span> unwrapped<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token namespace">std<span class="token punctuation">\\</span></span><span class="token function">print</span><span class="token punctuation">(</span>unwrapped<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre></div><p>You can downcast a value with the <code>as</code> operator.</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">final</span> <span class="token variable">anything</span><span class="token punctuation">:</span> <span class="token keyword">any</span> <span class="token operator">=</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">hello</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">;</span>

<span class="token comment">//...</span>

<span class="token keyword">if</span> <span class="token punctuation">(</span>anything <span class="token keyword">as</span> something<span class="token punctuation">:</span> <span class="token keyword">str</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token namespace">std<span class="token punctuation">\\</span></span><span class="token function">print</span><span class="token punctuation">(</span>something<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre></div><p><code>if</code> can also be inlined and act as an expression. However this expression does not support <code>null</code> unwrapping or downcasting (those are available in expressions using <code>??</code> and <code>as?</code>).</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">final</span> <span class="token variable">value</span> <span class="token operator">=</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>something <span class="token operator">&gt;</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token number">12</span> <span class="token keyword">else</span> <span class="token number">13</span><span class="token punctuation">;</span>
</code></pre></div><h2 id="match" tabindex="-1"><a class="header-anchor" href="#match" aria-hidden="true">#</a> <code>match</code></h2><p><code>match</code> selects the first branch whose condition matches the value. Each branch can list one or more conditions separated by commas.</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">final</span> <span class="token variable">category</span> <span class="token operator">=</span> <span class="token keyword">match</span> <span class="token punctuation">(</span>code<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token number">200</span> <span class="token operator">-&gt;</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">ok</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">,</span>
    <span class="token number">400</span><span class="token punctuation">,</span> <span class="token number">404</span> <span class="token operator">-&gt;</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">client error</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">,</span>
    <span class="token comment">// code is within this range</span>
    <span class="token number">500</span><span class="token operator">..</span><span class="token number">599</span> <span class="token operator">-&gt;</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">server error</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">,</span>
    <span class="token keyword">else</span> <span class="token operator">-&gt;</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">unknown</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre></div><p>It can also be used as a statement.</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">match</span> <span class="token punctuation">(</span>state<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">ready</span><span class="token string-punctuation punctuation">&quot;</span></span> <span class="token operator">-&gt;</span> <span class="token namespace">std<span class="token punctuation">\\</span></span><span class="token function">print</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">starting</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">done</span><span class="token string-punctuation punctuation">&quot;</span></span> <span class="token operator">-&gt;</span> <span class="token namespace">std<span class="token punctuation">\\</span></span><span class="token function">print</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">already finished</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    <span class="token keyword">else</span> <span class="token operator">-&gt;</span> <span class="token namespace">std<span class="token punctuation">\\</span></span><span class="token function">print</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">waiting</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">)</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>
</code></pre></div><p>A statement branch can use a lexical blocks:</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">var</span> <span class="token variable">result</span> <span class="token operator">=</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">unset</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">;</span>

<span class="token keyword">match</span> <span class="token punctuation">(</span>input<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token pattern regex"><span class="token regex-delimiter">$&quot;</span><span class="token regex-source language-regex">hello <span class="token char-class"><span class="token char-class-punctuation punctuation">[</span><span class="token range">a<span class="token range-punctuation operator">-</span>z</span><span class="token char-class-punctuation punctuation">]</span></span><span class="token quantifier number">+</span></span><span class="token regex-delimiter">&quot;</span></span> <span class="token operator">-&gt;</span> <span class="token punctuation">{</span>
        <span class="token keyword">final</span> <span class="token variable">branch</span> <span class="token operator">=</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">pattern</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">;</span>
        result <span class="token operator">=</span> branch<span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token keyword">else</span> <span class="token operator">-&gt;</span> <span class="token punctuation">{</span>
        result <span class="token operator">=</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">unknown</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>
</code></pre></div><p>How conditions are matched depends on the matched value:</p><ul><li>When matching a <code>str</code>, a <code>str</code> condition uses simple equality and a <code>pat</code> condition matches the string against the pattern.</li><li>When matching a <code>pat</code>, a <code>pat</code> condition uses simple equality and a <code>str</code> condition matches the pattern against the string.</li><li>When matching a number, a numeric condition uses simple equality and a <code>rg</code> condition matches when the number is contained in the range.</li><li>When matching a <code>type</code>, a <code>type</code> condition uses simple equality. Any other condition matches when the condition value is of the matched type.</li><li>When matching any other value, a <code>type</code> condition is checked as <code>value is Type</code>; other conditions use simple equality.</li></ul><p>For example:</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">final</span> <span class="token variable">greeting</span> <span class="token operator">=</span> <span class="token keyword">match</span> <span class="token punctuation">(</span><span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">hello joe</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token pattern regex"><span class="token regex-delimiter">$&quot;</span><span class="token regex-source language-regex">hello <span class="token char-class"><span class="token char-class-punctuation punctuation">[</span><span class="token range">a<span class="token range-punctuation operator">-</span>z</span><span class="token char-class-punctuation punctuation">]</span></span><span class="token quantifier number">+</span></span><span class="token regex-delimiter">&quot;</span></span> <span class="token operator">-&gt;</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">friendly</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">,</span>
    <span class="token keyword">else</span> <span class="token operator">-&gt;</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">unknown</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre></div><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">final</span> <span class="token variable">value</span><span class="token punctuation">:</span> <span class="token keyword">any</span> <span class="token operator">=</span> <span class="token number">42</span><span class="token punctuation">;</span>
<span class="token keyword">final</span> <span class="token variable">kind</span> <span class="token operator">=</span> <span class="token keyword">match</span> <span class="token punctuation">(</span>value<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token operator">&lt;</span><span class="token keyword">str</span><span class="token operator">&gt;</span> <span class="token operator">-&gt;</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">string</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">,</span>
    <span class="token operator">&lt;</span><span class="token keyword">int</span><span class="token operator">&gt;</span> <span class="token operator">-&gt;</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">integer</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">,</span>
    <span class="token keyword">else</span> <span class="token operator">-&gt;</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">other</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre></div><p><code>match</code> must be exhaustive. Use an <code>else</code> branch unless the compiler can prove that all possible cases are covered, such as every value of a boolean or every case of an enum.</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">enum</span> <span class="token class-name">Status</span> <span class="token punctuation">{</span>
    draft<span class="token punctuation">,</span>
    published<span class="token punctuation">,</span>
<span class="token punctuation">}</span>

<span class="token keyword">final</span> <span class="token variable">status</span> <span class="token operator">=</span> <span class="token class-name">Status</span><span class="token punctuation">.</span>published<span class="token punctuation">;</span>
<span class="token keyword">final</span> <span class="token variable">action</span> <span class="token operator">=</span> <span class="token keyword">match</span> <span class="token punctuation">(</span>status<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token punctuation">.</span>draft <span class="token operator">-&gt;</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">edit</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">,</span>
    <span class="token punctuation">.</span>published <span class="token operator">-&gt;</span> <span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">read</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre></div><h2 id="while-and-do-until" tabindex="-1"><a class="header-anchor" href="#while-and-do-until" aria-hidden="true">#</a> <code>while</code> and <code>do .. until</code></h2><p>Repeat a block of statements <code>while</code> or <code>until</code> a condition is <code>true</code>.</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">var</span> <span class="token variable">i</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token keyword">while</span> <span class="token punctuation">(</span>i <span class="token operator">&lt;</span> <span class="token number">10</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    i <span class="token operator">=</span> i <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">var</span> <span class="token variable">j</span> <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>
<span class="token keyword">do</span> <span class="token punctuation">{</span>
    j <span class="token operator">=</span> j <span class="token operator">-</span> <span class="token number">1</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span> <span class="token keyword">until</span> <span class="token punctuation">(</span>j <span class="token operator">==</span> <span class="token number">0</span><span class="token punctuation">)</span>
</code></pre></div><h2 id="for" tabindex="-1"><a class="header-anchor" href="#for" aria-hidden="true">#</a> <code>for</code></h2><p><code>for</code> is pretty much the same statement as in C.</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">for</span> <span class="token punctuation">(</span>i<span class="token punctuation">:</span> <span class="token keyword">int</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">10</span><span class="token punctuation">;</span> i <span class="token operator">=</span> i <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
    <span class="token keyword">break</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre></div><h2 id="foreach" tabindex="-1"><a class="header-anchor" href="#foreach" aria-hidden="true">#</a> <code>foreach</code></h2><p><code>foreach</code> can iterate over most data structures. The key/index variable can be omitted.</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">foreach</span> <span class="token punctuation">(</span>case <span class="token keyword">in</span> <span class="token class-name">SomeEnum</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
<span class="token punctuation">}</span>

<span class="token keyword">foreach</span> <span class="token punctuation">(</span>i<span class="token punctuation">,</span> value <span class="token keyword">in</span> listOfStrings<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
<span class="token punctuation">}</span>

<span class="token keyword">foreach</span> <span class="token punctuation">(</span>key<span class="token punctuation">,</span> value <span class="token keyword">in</span> aMap<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
<span class="token punctuation">}</span>

<span class="token keyword">foreach</span> <span class="token punctuation">(</span>i<span class="token punctuation">,</span> char <span class="token keyword">in</span> aString<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
<span class="token punctuation">}</span>

<span class="token keyword">final</span> <span class="token variable">fibonacciFib</span> <span class="token operator">=</span> <span class="token operator">&amp;</span><span class="token function">fibonacci</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">foreach</span> <span class="token punctuation">(</span>value <span class="token keyword">in</span> fibonacciFib<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
<span class="token punctuation">}</span>

<span class="token comment">// The key can be omitted</span>
<span class="token keyword">foreach</span> <span class="token punctuation">(</span>char <span class="token keyword">in</span> aString<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
<span class="token punctuation">}</span>

<span class="token keyword">foreach</span> <span class="token punctuation">(</span>i <span class="token keyword">in</span> <span class="token number">0</span><span class="token operator">..</span>n<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
<span class="token punctuation">}</span>
</code></pre></div><h2 id="break-and-continue" tabindex="-1"><a class="header-anchor" href="#break-and-continue" aria-hidden="true">#</a> <code>break</code> and <code>continue</code></h2><p><code>break</code> will stop a loop.</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">while</span> <span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>condition<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">break</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p><code>continue</code> will skip any following statement and start the loop again.</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">while</span> <span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>condition<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">continue</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token namespace">std<span class="token punctuation">\\</span></span><span class="token function">print</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">not reached if \`condition\` is true</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre></div><p>You can add a label to any loop and <code>break</code>/<code>continue</code> to it. This is useful when you have nested loops and want to break to an upper scope:</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">while</span> <span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span> <span class="token punctuation">:</span>here <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>condition<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">break</span> here<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token namespace">std<span class="token punctuation">\\</span></span><span class="token function">print</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string-punctuation punctuation">&quot;</span><span class="token string">not reached if \`condition\` is true</span><span class="token string-punctuation punctuation">&quot;</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre></div><h2 id="block-expression" tabindex="-1"><a class="header-anchor" href="#block-expression" aria-hidden="true">#</a> Block expression</h2><p>Block expressions are lexical blocks that produce a value:</p><div class="language-buzz" data-ext="buzz"><pre class="language-buzz"><code><span class="token keyword">var</span> <span class="token variable">value</span> <span class="token operator">=</span> <span class="token keyword">from</span> <span class="token punctuation">{</span>
    <span class="token comment">// Doing some work here...</span>

    <span class="token keyword">out</span> result<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre></div><p><code>out</code> must appear once at the end of the block.</p>`,44),e=[o];function c(u,l){return a(),s("div",null,e)}const k=n(p,[["render",c],["__file","control-flow.html.vue"]]);export{k as default};
